 * Mutex protégeant un compteur partagé entre threads.
 * pthread_mutex_lock/unlock encadrent la section critique.
 * =========================================================== */
static pthread_mutex_t lock = PTHREAD_MUTEX_INITIALIZER;
static int counter = 0;

void *increment_worker(void *arg) {
    (void)arg;
    pthread_mutex_lock(&lock);
    counter++;
    pthread_mutex_unlock(&lock);
    return NULL;
}

int main(void) {
    /* Test 1 : lock/unlock basique */
    pthread_mutex_t m = PTHREAD_MUTEX_INITIALIZER;
    int r1 = pthread_mutex_lock(&m);
    int r2 = pthread_mutex_unlock(&m);
    printf("lock=%d unlock=%d\n", r1, r2);
    pthread_mutex_destroy(&m);

    /* Test 2 : compteur protégé par 2 threads */
    pthread_t t1, t2;
    counter = 0;
    pthread_create(&t1, NULL, increment_worker, NULL);
    pthread_create(&t2, NULL, increment_worker, NULL);
    pthread_join(t1, NULL);
    pthread_join(t2, NULL);
    printf("counter=%d\n", counter);
    return 0;
}
